`include "SPI_Master_With_Single_CS.v" 
`include "AesIterative.v"

module cmac_handshake ( 
    input clk, 
    input rst, 
    input in, 
    output reg lock_state, // 0 = locked, 1 = unlocked
    // SPI Interface 
    output o_SPI_Clk, 
    input i_SPI_MISO, 
    output o_SPI_MOSI, 
    output o_SPI_CS_n 
    // ASG Interface 
    //... 
    // AES Interface 
    //... 
